exercises.solution_code:
def make_user():
    # Build and return a brand-new user dict every call. Returning a fresh
    # object (not a shared module-level one) is what lets a function-scoped
    # fixture hand each test its own independent value.
    return {"name": "ada", "roles": [], "active": True}

def db_session(log):
    # The body of a `yield` fixture: setup runs before the yield, the yielded
    # value is the resource the test receives, and the code after the yield is
    # teardown. `try/finally` guarantees teardown runs even if the test fails.
    log.append("connect")
    session = {"rows": []}
    try:
        yield session
    finally:
        log.append("close")

